  const chatwootAccountId = compact(current.chatwoot_account_id || '2') || '1';
  const chatwootApiToken = compact(current.chatwoot_api_token);
  const mediaCount = Number(current.media_count || 0);
  const lastMsgId = Number(current.chatwoot_message_id || 0);
  const chatwootBaseUrl = 'https://chat.depaseoenfincas.raaamp.co';

  if (!chatwootId || !chatwootApiToken || mediaCount <= 0 || !lastMsgId) {
    console.log('[delivery-check] missing fields — fallback 5s wait', { chatwootId: !!chatwootId, hasToken: !!chatwootApiToken, mediaCount, lastMsgId });
    await new Promise((resolve) => setTimeout(resolve, 5000));
    return [{ json: current }];
  }

  // The just-sent group occupies message ids [lastMsgId - mediaCount + 1 .. lastMsgId].
  // We poll Chatwoot until ALL of those ids report status 'delivered' or 'read'.
  const groupIds = new Set();
  for (let k = 0; k < mediaCount; k++) groupIds.add(lastMsgId - k);

  const MAX_RETRIES = 12;
  const RETRY_INTERVAL_MS = 5000;
  const messagesUrl = chatwootBaseUrl + '/api/v1/accounts/' + chatwootAccountId + '/conversations/' + chatwootId + '/messages';

  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        url: messagesUrl, method: 'GET',
        headers: { api_access_token: chatwootApiToken, Accept: 'application/json' },
        json: true, timeout: 10000, ignoreHttpStatusErrors: true,
      });
      const messages = (resp && resp.payload) || resp || [];
      const groupMessages = messages.filter((m) => groupIds.has(Number(m.id)));
      const deliveredCount = groupMessages.filter((m) => m.status === 'delivered' || m.status === 'read').length;

      if (deliveredCount >= mediaCount) {
        console.log('[delivery-check] all ' + mediaCount + ' delivered for ' + compact(current.property_id) + ' (attempt ' + attempt + ')');
        return [{ json: current }];
      }
      console.log('[delivery-check] ' + deliveredCount + '/' + mediaCount + ' delivered (' + compact(current.property_id) + ') attempt ' + attempt);
    } catch (err) {
      console.log('[delivery-check] error attempt ' + attempt + ': ' + (err.message || err));
    }
    if (attempt < MAX_RETRIES) await new Promise((resolve) => setTimeout(resolve, RETRY_INTERVAL_MS));
  }
  console.log('[delivery-check] timeout for ' + compact(current.property_id) + ', proceeding anyway');
  return [{ json: current }];
}

// Default 350ms throttle so WhatsApp doesn't reorder a burst of plain texts.
await new Promise((resolve) => setTimeout(resolve, 350));
return [{ json: current }];

